-- Logginhood test data
-- Run in Supabase SQL editor

-- CLUBS
ON CONFLICT (name) DO UPDATE SET name = EXCLUDED.name RETURNING id;

-- AUTH USERS (test accounts — no real login needed)
ON CONFLICT (id) DO NOTHING;

-- PROFILES
ON CONFLICT (id) DO UPDATE SET full_name=EXCLUDED.full_name, gender=EXCLUDED.gender, bow_type=EXCLUDED.bow_type, age_category=EXCLUDED.age_category, club_id=EXCLUDED.club_id;

-- CLUB MEMBERS
ON CONFLICT (profile_id, club_id) DO NOTHING;

-- SCORES
ON CONFLICT (id) DO NOTHING;

-- Done! Generated 252 members across 20 clubs.
-- Total scores: 11340